function solve(n: number, edges: number[][], k: number): number {
    // Build the graph
    const graph: Map<number, [number, number][]> = new Map();
    for (const [u, v, w] of edges) {
        if (!graph.has(u)) graph.set(u, []);
        if (!graph.has(v)) graph.set(v, []);
        graph.get(u)!.push([v, w]);
        graph.get(v)!.push([u, w]);
    }

    // Sort edges by weight
    const sortedEdges = [...edges].sort((a, b) => a[2] - b[2]);

    // Union-Find (Disjoint Set Union) data structure
    const parent: number[] = Array(n).fill(0).map((_, i) => i);
    const rank: number[] = Array(n).fill(1);

    function find(x: number): number {
        if (parent[x] !== x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    function union(x: number, y: number): boolean {
        const xRoot = find(x);
        const yRoot = find(y);
        if (xRoot === yRoot) {
            return false;
        }
        if (rank[xRoot] < rank[yRoot]) {
            parent[xRoot] = yRoot;
        } else {
            parent[yRoot] = xRoot;
            rank[xRoot] += rank[yRoot];
        }
        return true;
    }

    // Kruskal's algorithm to find the minimum maximum edge weight
    let maxCost = 0;
    let components = n;
    for (const [u, v, w] of sortedEdges) {
        if (union(u, v)) {
            components--;
            maxCost = Math.max(maxCost, w);
            if (components === k) {
                break;
            }
        }
    }

    return maxCost;
}
